import React from 'react';
import  Condition  from './Condition';
const Content = ({ items, handleChange, changeDelete }) => {
  return (
    <main className="Contents">{(items.length) ? (<Condition items={items} changeDelete={changeDelete} handleChange={handleChange}/>) : (<p>Done All Activity Quickly</p>)}
    
    <Additems/>
    </main>
  );
};

export default Content;
